# -*- coding: utf-8 -*-
"""
agent_init.py — Ajan başlatma modülü.

Credential pool yükleme, plugin başlatma, ortam hazırlama
işlemlerini yöneten AgentInitializer sınıfını içerir.
"""

import os
import sys
import json
import time
import logging
from pathlib import Path
from typing import Optional, Dict, Any

logger = logging.getLogger(__name__)


class AgentInitializer:
    """
    Ajan başlatma yöneticisi.

    Credential pool'u yükler, plugin'leri başlatır,
    ortam değişkenlerini hazırlar.
    """

    def __init__(self, config_path: Optional[str] = None):
        """
        AgentInitializer başlatıcı.

        Args:
            config_path: Yapılandırma dosyası yolu (None ise varsayılan)
        """
        self._basarili = False
        self._hata = None
        self._baslangic_zamani = None
        self._plugin_durumlari: Dict[str, bool] = {}
        self._ortam_degiskenleri: Dict[str, str] = {}
        self._config = self._config_yukle(config_path)
        self._credential_pool: Dict[str, Any] = {}

    def _config_yukle(self, config_path: Optional[str]) -> Dict[str, Any]:
        """Yapilandirma dosyasini yukler."""
        try:
            if config_path and os.path.exists(config_path):
                with open(config_path, "r", encoding="utf-8") as f:
                    return json.load(f)
            return {"debug": False, "timeout": 30, "plugin_dizini": "plugins"}
        except (json.JSONDecodeError, IOError) as e:
            logger.warning(f"Config yuklenemedi: {e}, varsayilan kullaniliyor")
            return {"debug": False, "timeout": 30, "plugin_dizini": "plugins"}

    def baslat(self) -> bool:
        """
        Ajani baslatir: credential yukle, plugin'leri baslat, ortami hazirla.

        Returns:
            bool: Basarili ise True
        """
        try:
            self._baslangic_zamani = time.time()
            logger.info("Agent baslatiliyor...")

            # 1. Credential pool yukle
            self._credential_yukle()

            # 2. Ortam degiskenlerini hazirla
            self._ortam_hazirla()

            # 3. Plugin'leri baslat
            self._plugin_baslat()

            self._basarili = True
            sure = time.time() - self._baslangic_zamani
            logger.info(f"Agent basariyla baslatildi ({sure:.2f}s)")
            return True

        except Exception as e:
            self._hata = str(e)
            logger.error(f"Agent baslatilamadi: {e}")
            return False

    def _credential_yukle(self) -> None:
        """Credential pool'u yukler."""
        try:
            env_path = os.getenv("CREDENTIAL_FILE", ".env")
            if os.path.exists(env_path):
                with open(env_path, "r", encoding="utf-8") as f:
                    for line in f:
                        line = line.strip()
                        if line and not line.startswith("#") and "=" in line:
                            key, val = line.split("=", 1)
                            self._credential_pool[key.strip()] = val.strip()
            logger.info(f"Credential pool yuklendi: {len(self._credential_pool)} anahtar")
        except Exception as e:
            logger.warning(f"Credential yuklenemedi: {e}")

    def _ortam_hazirla(self) -> None:
        """Ortam degiskenlerini hazirlar."""
        try:
            for key, val in self._credential_pool.items():
                if key not in os.environ:
                    os.environ[key] = val
                    self._ortam_degiskenleri[key] = val
        except Exception as e:
            logger.warning(f"Ortam hazirlanamadi: {e}")

    def _plugin_baslat(self) -> None:
        """Plugin'leri baslatir."""
        try:
            plugin_dizini = self._config.get("plugin_dizini", "plugins")
            if os.path.isdir(plugin_dizini):
                sys.path.insert(0, os.path.abspath(plugin_dizini))
                for dosya in sorted(os.listdir(plugin_dizini)):
                    if dosya.endswith(".py") and not dosya.startswith("_"):
                        modul_adi = dosya[:-3]
                        try:
                            __import__(modul_adi)
                            self._plugin_durumlari[modul_adi] = True
                        except ImportError as e:
                            self._plugin_durumlari[modul_adi] = False
                            logger.warning(f"Plugin yuklenemedi: {modul_adi}: {e}")
            logger.info(f"Plugin durumu: {sum(self._plugin_durumlari.values())} aktif")
        except Exception as e:
            logger.warning(f"Plugin baslatilamadi: {e}")

    def durum(self) -> Dict[str, Any]:
        """
        Mevcut ajan durumunu dondurur.

        Returns:
            dict: Durum bilgileri
        """
        try:
            return {
                "basarili": self._basarili,
                "hata": self._hata,
                "calisma_suresi": time.time() - self._baslangic_zamani if self._baslangic_zamani else 0,
                "credential_sayisi": len(self._credential_pool),
                "plugin_sayisi": len(self._plugin_durumlari),
                "aktif_plugin": sum(1 for v in self._plugin_durumlari.values() if v),
                "ortam_degiskenleri": len(self._ortam_degiskenleri),
            }
        except Exception as e:
            return {"hata": str(e)}

    def yeniden_baslat(self) -> bool:
        """
        Ajani yeniden baslatir.

        Returns:
            bool: Basarili ise True
        """
        try:
            logger.info("Agent yeniden baslatiliyor...")
            self._basarili = False
            self._hata = None
            self._plugin_durumlari.clear()
            self._ortam_degiskenleri.clear()
            self._credential_pool.clear()
            return self.baslat()
        except Exception as e:
            self._hata = str(e)
            logger.error(f"Yeniden baslatma hatasi: {e}")
            return False

    def credential_pool(self) -> Dict[str, Any]:
        """Credential pool'u dondurur."""
        return dict(self._credential_pool)

    def plugin_durumlari(self) -> Dict[str, bool]:
        """Plugin durumlarini dondurur."""
        return dict(self._plugin_durumlari)


def run(**kwargs) -> str:
    """
    AgentInitializer'i calistirir.

    Args:
        **kwargs: config_path gibi parametreler

    Returns:
        str: Baslatma sonucu
    """
    try:
        config_path = kwargs.get("config_path")
        init = AgentInitializer(config_path=config_path)
        basarili = init.baslat()
        durum = init.durum()
        if basarili:
            return (f"Agent basariyla baslatildi. "
                    f"{durum['credential_sayisi']} credential, "
                    f"{durum['aktif_plugin']} plugin aktif.")
        return f"Agent baslatilamadi: {durum.get('hata', 'bilinmeyen hata')}"
    except Exception as e:
        return f"Kritik hata: {e}"

